/**
 * @file SearchService.h
 * @brief Centralized search service for IntraLedger BlogSuite
 *
 * This file defines the SearchService class that consolidates all search-related
 * functionality including document indexing and query processing. The service
 * maintains an in-memory inverted index for efficient full-text search operations.
 *
 * Copyright © 2024 IntraLedger
 */

#ifndef INTRALEDGER_SEARCH_SERVICE_H
#define INTRALEDGER_SEARCH_SERVICE_H

#include <map>
#include <mutex>
#include <shared_mutex>
#include <string>
#include <vector>

namespace intraledger::search {

/**
 * @class SearchService
 * @brief Centralized service for document indexing and search query processing
 *
 * The SearchService maintains an in-memory inverted index that maps tokens to
 * document IDs. It provides methods for indexing documents and executing search
 * queries against the indexed content.
 *
 * Thread-safety: All public methods are thread-safe for concurrent access.
 */
class SearchService {
public:
    /**
     * @brief Get the singleton instance of SearchService
     * @return Reference to the global SearchService instance
     */
    static SearchService& instance();

    /**
     * @brief Index a document for full-text search
     *
     * Tokenizes the document content and adds it to the inverted index.
     * If the document was previously indexed, the old index entries are
     * replaced with new ones.
     *
     * @param documentId Unique identifier for the document
     * @param documentContent The text content to be indexed
     */
    void indexDocument(int documentId, const std::string& documentContent);

    /**
     * @brief Execute a search query against the indexed documents
     *
     * Tokenizes the search term and finds all documents containing
     * the specified terms. Results are returned sorted by relevance
     * (number of matching terms).
     *
     * @param searchTerm The search query string
     * @return Vector of document IDs that match the query, sorted by relevance
     */
    std::vector<int> query(const std::string& searchTerm);

    /**
     * @brief Remove a document from the search index
     * @param documentId The ID of the document to remove
     */
    void removeDocument(int documentId);

    /**
     * @brief Clear all indexed documents
     */
    void clearIndex();

    /**
     * @brief Get the number of indexed documents
     * @return Count of unique documents in the index
     */
    std::size_t documentCount() const;

    // Prevent copying and moving
    SearchService(const SearchService&) = delete;
    SearchService& operator=(const SearchService&) = delete;
    SearchService(SearchService&&) = delete;
    SearchService& operator=(SearchService&&) = delete;

private:
    SearchService() = default;
    ~SearchService() = default;

    /**
     * @brief Tokenize text into searchable terms
     *
     * Splits text on whitespace and punctuation, converts to lowercase,
     * and filters out very short tokens.
     *
     * @param text The text to tokenize
     * @return Vector of normalized tokens
     */
    static std::vector<std::string> tokenize(const std::string& text);

    /// Inverted index: token -> list of document IDs
    std::map<std::string, std::vector<int>> invertedIndex;

    /// Mutex for thread-safe access to the inverted index
    mutable std::shared_mutex indexMutex;
};

} // namespace intraledger::search

#endif // INTRALEDGER_SEARCH_SERVICE_H

/**
 * @file SearchService.h
 * @brief Centralized search service for IntraLedger BlogSuite
 *
 * This file defines the SearchService class that consolidates all search-related
 * functionality including document indexing and query processing. The service
 * maintains an in-memory inverted index for efficient full-text search operations.
 *
 * This refactoring consolidates search logic previously scattered across:
 *   - module_18.cpp (search query parser)
 *   - module_41.cpp (search service and ranking)
 *   - module_61.cpp (search DSL and SQL translation)
 *
 * Copyright © 2024 IntraLedger
 */

#ifndef INTRALEDGER_SEARCH_SERVICE_H
#define INTRALEDGER_SEARCH_SERVICE_H

#include <algorithm>
#include <cctype>
#include <map>
#include <mutex>
#include <shared_mutex>
#include <string>
#include <unordered_map>
#include <unordered_set>
#include <vector>

namespace intraledger::search {

/**
 * @class SearchService
 * @brief Centralized service for document indexing and search query processing
 *
 * The SearchService maintains an in-memory inverted index that maps tokens to
 * document IDs. It provides methods for indexing documents and executing search
 * queries against the indexed content.
 *
 * Thread-safety: All public methods are thread-safe for concurrent access.
 */
class SearchService {
public:
    /**
     * @brief Get the singleton instance of SearchService
     * @return Reference to the global SearchService instance
     */
    static SearchService& instance();

    /**
     * @brief Index a document for full-text search
     *
     * Tokenizes the document content and adds it to the inverted index.
     * If the document was previously indexed, the old index entries are
     * replaced with new ones.
     *
     * @param documentId Unique identifier for the document
     * @param documentContent The text content to be indexed
     */
    void indexDocument(int documentId, const std::string& documentContent);

    /**
     * @brief Execute a search query against the indexed documents
     *
     * Tokenizes the search term and finds all documents containing
     * the specified terms. Results are returned sorted by relevance
     * (number of matching terms).
     *
     * @param searchTerm The search query string
     * @return Vector of document IDs that match the query, sorted by relevance
     */
    std::vector<int> query(const std::string& searchTerm);

    /**
     * @brief Remove a document from the search index
     * @param documentId The ID of the document to remove
     */
    void removeDocument(int documentId);

    /**
     * @brief Clear all indexed documents
     */
    void clearIndex();

    /**
     * @brief Get the number of indexed documents
     * @return Count of unique documents in the index
     */
    std::size_t documentCount() const;

    // Prevent copying and moving
    SearchService(const SearchService&) = delete;
    SearchService& operator=(const SearchService&) = delete;
    SearchService(SearchService&&) = delete;
    SearchService& operator=(SearchService&&) = delete;

private:
    SearchService() = default;
    ~SearchService() = default;

    /**
     * @brief Tokenize text into searchable terms
     *
     * Splits text on whitespace and punctuation, converts to lowercase,
     * and filters out very short tokens.
     *
     * @param text The text to tokenize
     * @return Vector of normalized tokens
     */
    static std::vector<std::string> tokenize(const std::string& text);

    /// Inverted index: token -> list of document IDs
    std::map<std::string, std::vector<int>> invertedIndex;

    /// Set of all indexed document IDs
    std::unordered_set<int> indexedDocuments;

    /// Mutex for thread-safe access to the inverted index
    mutable std::shared_mutex indexMutex;
};

} // namespace intraledger::search

#endif // INTRALEDGER_SEARCH_SERVICE_H

/**
 * @file SearchService.cpp
 * @brief Implementation of the centralized SearchService for IntraLedger BlogSuite
 *
 * This implementation consolidates search-related logic that was previously
 * scattered across multiple modules:
 *   - Tokenization logic from module_18.cpp and module_61.cpp
 *   - Inverted index management from module_41.cpp
 *   - Query processing and ranking
 *
 * Copyright © 2024 IntraLedger
 */

#include "SearchService.h"
#include <algorithm>
#include <cctype>
#include <unordered_map>

namespace intraledger::search {

SearchService& SearchService::instance() {
    static SearchService instance;
    return instance;
}

void SearchService::indexDocument(int documentId, const std::string& documentContent) {
    // Tokenize the document content
    std::vector<std::string> tokens = tokenize(documentContent);

    // Get unique tokens for this document
    std::unordered_set<std::string> uniqueTokens(tokens.begin(), tokens.end());

    std::unique_lock<std::shared_mutex> lock(indexMutex);

    // If document was previously indexed, remove old entries
    if (indexedDocuments.count(documentId) > 0) {
        for (auto& [token, docIds] : invertedIndex) {
            auto it = std::find(docIds.begin(), docIds.end(), documentId);
            if (it != docIds.end()) {
                docIds.erase(it);
            }
        }
    }

    // Add new index entries
    for (const auto& token : uniqueTokens) {
        auto& docIds = invertedIndex[token];
        if (std::find(docIds.begin(), docIds.end(), documentId) == docIds.end()) {
            docIds.push_back(documentId);
        }
    }

    // Track this document as indexed
    indexedDocuments.insert(documentId);
}

std::vector<int> SearchService::query(const std::string& searchTerm) {
    if (searchTerm.empty()) {
        return {};
    }

    // Tokenize the search query
    std::vector<std::string> tokens = tokenize(searchTerm);

    if (tokens.empty()) {
        return {};
    }

    // Score documents by number of matching terms (TF scoring)
    std::unordered_map<int, std::size_t> scoreTable;

    {
        std::shared_lock<std::shared_mutex> lock(indexMutex);

        for (const auto& token : tokens) {
            auto it = invertedIndex.find(token);
            if (it != invertedIndex.end()) {
                for (int docId : it->second) {
                    ++scoreTable[docId];
                }
            }
        }
    }

    // Convert to vector and sort by score (descending)
    std::vector<std::pair<int, std::size_t>> ranked(scoreTable.begin(), scoreTable.end());
    std::sort(ranked.begin(), ranked.end(),
              [](const auto& a, const auto& b) { return a.second > b.second; });

    // Extract document IDs in ranked order
    std::vector<int> result;
    result.reserve(ranked.size());
    for (const auto& [docId, score] : ranked) {
        result.push_back(docId);
    }

    return result;
}

void SearchService::removeDocument(int documentId) {
    std::unique_lock<std::shared_mutex> lock(indexMutex);

    // Remove document from all posting lists
    for (auto& [token, docIds] : invertedIndex) {
        auto it = std::find(docIds.begin(), docIds.end(), documentId);
        if (it != docIds.end()) {
            docIds.erase(it);
        }
    }

    // Remove from tracked documents
    indexedDocuments.erase(documentId);
}

void SearchService::clearIndex() {
    std::unique_lock<std::shared_mutex> lock(indexMutex);
    invertedIndex.clear();
    indexedDocuments.clear();
}

std::size_t SearchService::documentCount() const {
    std::shared_lock<std::shared_mutex> lock(indexMutex);
    return indexedDocuments.size();
}

std::vector<std::string> SearchService::tokenize(const std::string& text) {
    std::vector<std::string> tokens;
    std::string currentToken;
    currentToken.reserve(32);

    auto flushToken = [&]() {
        if (currentToken.size() >= 2) {  // Filter out very short tokens
            // Convert to lowercase
            std::transform(currentToken.begin(), currentToken.end(), currentToken.begin(),
                          [](unsigned char c) { return static_cast<char>(std::tolower(c)); });
            tokens.push_back(std::move(currentToken));
        }
        currentToken.clear();
    };

    for (char ch : text) {
        if (std::isalnum(static_cast<unsigned char>(ch))) {
            currentToken.push_back(ch);
        } else {
            flushToken();
        }
    }
    flushToken();  // Don't forget the last token

    return tokens;
}

} // namespace intraledger::search

/*
 *  IntraLedger BlogSuite – Search Query Parser (Refactored)
 *
 *  File:        src/module_18.cpp
 *  Author:      IntraLedger Core Team
 *  Description: Implements a boolean-aware, phrase-capable search query parser
 *               that folds to a parametrized SQL WHERE fragment consumable
 *               by the Repository/ORM layer.  The parser recognises:
 *
 *                 • Logical AND, OR, NOT   (case-insensitive, symbolic &&, ||, !)
 *                 • Parenthesis for precedence grouping
 *                 • Double-quoted phrases
 *                 • Plain words with automatic wildcard suffix
 *
 *               The output is safe for prepared statements; parameters are
 *               emitted separately to avoid SQL-injection.
 *
 *  REFACTORING NOTE:
 *               Search indexing functionality has been consolidated into the
 *               centralized SearchService (src/search/SearchService.h).
 *               This module now delegates indexing operations to SearchService.
 *
 *  Copyright © 2024 IntraLedger
 */

#include <algorithm>
#include <cctype>
#include <memory>
#include <optional>
#include <sstream>
#include <stdexcept>
#include <string>
#include <string_view>
#include <unordered_set>
#include <utility>
#include <vector>

#include "search/SearchService.h"

namespace intraledger::search
{

// -------------------------------------------------
// Utilities
// -------------------------------------------------

namespace detail
{
inline std::string to_lower(std::string_view sv)
{
    std::string out;
    out.reserve(sv.size());
    std::transform(sv.begin(), sv.end(), std::back_inserter(out),
                   [](unsigned char ch) { return static_cast<char>(std::tolower(ch)); });
    return out;
}

inline bool iequals(std::string_view a, std::string_view b)
{
    return to_lower(a) == to_lower(b);
}

} // namespace detail

// -------------------------------------------------
// Tokenizer
// -------------------------------------------------

enum class TokenType
{
    Word,
    Phrase,
    And,
    Or,
    Not,
    LParen,
    RParen,
    End,
};

struct Token
{
    TokenType            type;
    std::string          lexeme;
};

class Tokenizer
{
public:
    explicit Tokenizer(std::string_view q) : _query(q), _pos(0) {}

    Token next_token()
    {
        consume_ws();

        if (_pos >= _query.size())
            return {TokenType::End, ""};

        char c = _query[_pos];

        // Parenthesis
        if (c == '(')
        {
            ++_pos;
            return {TokenType::LParen, "("};
        }
        if (c == ')')
        {
            ++_pos;
            return {TokenType::RParen, ")"};
        }

        // Symbolic operators
        if (c == '&' && peek(1) == '&')
        {
            _pos += 2;
            return {TokenType::And, "&&"};
        }
        if (c == '|' && peek(1) == '|')
        {
            _pos += 2;
            return {TokenType::Or, "||"};
        }
        if (c == '!')
        {
            ++_pos;
            return {TokenType::Not, "!"};
        }

        // Quoted phrase
        if (c == '"')
        {
            ++_pos;
            std::size_t start = _pos;
            while (_pos < _query.size() && _query[_pos] != '"')
            {
                if (_query[_pos] == '\\' && _pos + 1 < _query.size())
                    _pos += 2; // Skip escaped char
                else
                    ++_pos;
            }

            if (_pos >= _query.size())
                throw std::runtime_error("Unterminated quote in search query");

            std::string phrase;
            phrase.reserve(_pos - start);
            for (std::size_t i = start; i < _pos; ++i)
            {
                char ch = _query[i];
                if (ch == '\\' && i + 1 < _pos)
                {
                    phrase.push_back(_query[i + 1]);
                    ++i;
                }
                else
                {
                    phrase.push_back(ch);
                }
            }

            ++_pos; // Skip closing quote
            return {TokenType::Phrase, phrase};
        }

        // Word or textual operator
        std::size_t start = _pos;
        while (_pos < _query.size() && is_word_char(_query[_pos]))
            ++_pos;

        if (start == _pos)
            throw std::runtime_error("Unexpected character in search query");

        std::string word(_query.substr(start, _pos - start));

        // Check textual operators (AND/OR/NOT)
        if (detail::iequals(word, "AND"))
            return {TokenType::And, word};
        if (detail::iequals(word, "OR"))
            return {TokenType::Or, word};
        if (detail::iequals(word, "NOT"))
            return {TokenType::Not, word};

        return {TokenType::Word, std::move(word)};
    }

private:
    static bool is_word_char(char c)
    {
        return std::isalnum(static_cast<unsigned char>(c)) || c == '_' || c == '-';
    }

    char peek(std::size_t offset) const
    {
        if (_pos + offset >= _query.size())
            return '\0';
        return _query[_pos + offset];
    }

    void consume_ws()
    {
        while (_pos < _query.size() && std::isspace(static_cast<unsigned char>(_query[_pos])))
            ++_pos;
    }

    std::string_view _query;
    std::size_t      _pos;
};

// -------------------------------------------------
// AST
// -------------------------------------------------

struct Node
{
    virtual ~Node() = default;
};

using NodePtr = std::unique_ptr<Node>;

struct WordNode final : Node
{
    explicit WordNode(std::string w) : word(std::move(w)) {}
    std::string word;
};

struct PhraseNode final : Node
{
    explicit PhraseNode(std::string p) : phrase(std::move(p)) {}
    std::string phrase;
};

struct UnaryNode : Node
{
    explicit UnaryNode(NodePtr c) : child(std::move(c)) {}
    NodePtr child;
};

struct BinaryNode : Node
{
    BinaryNode(NodePtr l, NodePtr r) : left(std::move(l)), right(std::move(r)) {}
    NodePtr left;
    NodePtr right;
};

struct AndNode final : BinaryNode
{
    using BinaryNode::BinaryNode;
};

struct OrNode final : BinaryNode
{
    using BinaryNode::BinaryNode;
};

struct NotNode final : UnaryNode
{
    using UnaryNode::UnaryNode;
};

// -------------------------------------------------
// Parser (Recursive Descent LL(1))
// -------------------------------------------------

class Parser
{
public:
    explicit Parser(Tokenizer tz) : _tz(std::move(tz)), _curr(_tz.next_token()) {}

    NodePtr parse()
    {
        auto expr = parse_or();
        if (_curr.type != TokenType::End)
            throw std::runtime_error("Unexpected token after end of expression");
        return expr;
    }

private:
    // OR  → AND ( (OR) AND )*
    NodePtr parse_or()
    {
        NodePtr node = parse_and();
        while (_curr.type == TokenType::Or)
        {
            consume(TokenType::Or);
            NodePtr rhs = parse_and();
            node         = std::make_unique<OrNode>(std::move(node), std::move(rhs));
        }
        return node;
    }

    // AND → UNARY ( (AND) UNARY )*
    NodePtr parse_and()
    {
        NodePtr node = parse_unary();
        while (_curr.type == TokenType::And ||
               _curr.type == TokenType::Word ||
               _curr.type == TokenType::Phrase ||
               _curr.type == TokenType::LParen ||
               _curr.type == TokenType::Not)
        {
            // Implicit AND if next token starts another term
            if (_curr.type == TokenType::And)
                consume(TokenType::And);
            NodePtr rhs = parse_unary();
            node         = std::make_unique<AndNode>(std::move(node), std::move(rhs));
        }
        return node;
    }

    // UNARY → NOT UNARY | PRIMARY
    NodePtr parse_unary()
    {
        if (_curr.type == TokenType::Not)
        {
            consume(TokenType::Not);
            NodePtr operand = parse_unary();
            return std::make_unique<NotNode>(std::move(operand));
        }
        return parse_primary();
    }

    // PRIMARY → WORD | PHRASE | '(' OR ')'
    NodePtr parse_primary()
    {
        switch (_curr.type)
        {
        case TokenType::Word:
        {
            std::string w = _curr.lexeme;
            consume(TokenType::Word);
            return std::make_unique<WordNode>(std::move(w));
        }
        case TokenType::Phrase:
        {
            std::string p = _curr.lexeme;
            consume(TokenType::Phrase);
            return std::make_unique<PhraseNode>(std::move(p));
        }
        case TokenType::LParen:
        {
            consume(TokenType::LParen);
            NodePtr node = parse_or();
            consume(TokenType::RParen);
            return node;
        }
        default:
            throw std::runtime_error("Unexpected token in primary expression");
        }
    }

    void consume(TokenType expected)
    {
        if (_curr.type != expected)
            throw std::runtime_error("Unexpected token while parsing search query");
        _curr = _tz.next_token();
    }

    Tokenizer _tz;
    Token     _curr;
};

// -------------------------------------------------
// SQL Generator (simple visitor)
// -------------------------------------------------

class SqlEmitter
{
public:
    struct Result
    {
        std::string              where_fragment;
        std::vector<std::string> parameters;
    };

    static Result generate(const NodePtr& root, const std::string& column)
    {
        SqlEmitter emitter(column);
        emitter.visit(root.get());
        return {std::move(emitter._buffer), std::move(emitter._params)};
    }

private:
    explicit SqlEmitter(std::string col) : _column(std::move(col)) {}

    void visit(const Node* n)
    {
        if (dynamic_cast<const WordNode*>(n))
            visit_word(static_cast<const WordNode*>(n));
        else if (dynamic_cast<const PhraseNode*>(n))
            visit_phrase(static_cast<const PhraseNode*>(n));
        else if (dynamic_cast<const AndNode*>(n))
            visit_and(static_cast<const AndNode*>(n));
        else if (dynamic_cast<const OrNode*>(n))
            visit_or(static_cast<const OrNode*>(n));
        else if (dynamic_cast<const NotNode*>(n))
            visit_not(static_cast<const NotNode*>(n));
        else
            throw std::runtime_error("Unknown node type in SQL emitter");
    }

    void visit_word(const WordNode* node)
    {
        append_condition("ILIKE");
        _params.push_back('%' + node->word + '%');
    }

    void visit_phrase(const PhraseNode* node)
    {
        append_condition("ILIKE");
        _params.push_back('%' + node->phrase + '%');
    }

    void visit_not(const NotNode* node)
    {
        _buffer += "NOT (";
        visit(node->child.get());
        _buffer += ")";
    }

    void visit_and(const AndNode* node)
    {
        _buffer += "(";
        visit(node->left.get());
        _buffer += " AND ";
        visit(node->right.get());
        _buffer += ")";
    }

    void visit_or(const OrNode* node)
    {
        _buffer += "(";
        visit(node->left.get());
        _buffer += " OR ";
        visit(node->right.get());
        _buffer += ")";
    }

    void append_condition(const char* comparator)
    {
        _buffer += _column;
        _buffer += ' ';
        _buffer += comparator;
        _buffer += " ?";
    }

    std::string              _column;
    std::string              _buffer;
    std::vector<std::string> _params;
};

// -------------------------------------------------
// Public Facade
// -------------------------------------------------

class ParsedQuery
{
public:
    ParsedQuery(std::string  where,
                std::vector<std::string> params)
        : _where(std::move(where)),
          _params(std::move(params))
    {}

    const std::string& where_clause() const noexcept { return _where; }
    const std::vector<std::string>& params() const noexcept { return _params; }

private:
    std::string              _where;
    std::vector<std::string> _params;
};

class QueryParser
{
public:
    ParsedQuery compile(std::string_view raw_query,
                        const std::string& target_column = "content")
    {
        if (raw_query.empty())
            throw std::invalid_argument("Search query may not be empty");

        Tokenizer tokenizer(raw_query);
        Parser    parser(std::move(tokenizer));
        NodePtr   root = parser.parse();

        auto result = SqlEmitter::generate(root, target_column);

        if (result.where_fragment.empty())
            result.where_fragment = "TRUE"; // Match all (should not occur)

        return ParsedQuery{std::move(result.where_fragment),
                           std::move(result.parameters)};
    }
};

// -------------------------------------------------
// Convenience – Highlighting Helper
// -------------------------------------------------

std::string highlight_terms(std::string_view text,
                            const std::vector<std::string>& terms,
                            std::string_view open_tag = "<mark>",
                            std::string_view close_tag = "</mark>")
{
    if (terms.empty())
        return std::string(text);

    // Build lowercase copy of the text for case-insensitive search
    std::string lowered = detail::to_lower(text);
    std::string result;
    result.reserve(text.size() + 16 * terms.size());

    std::size_t pos = 0;
    while (pos < text.size())
    {
        std::size_t nearest = std::string::npos;
        std::size_t term_idx = 0;

        for (std::size_t i = 0; i < terms.size(); ++i)
        {
            std::string term_lower = detail::to_lower(terms[i]);
            std::size_t p          = lowered.find(term_lower, pos);
            if (p != std::string::npos && (nearest == std::string::npos || p < nearest))
            {
                nearest  = p;
                term_idx = i;
            }
        }

        if (nearest == std::string::npos)
        {
            result.append(text.substr(pos));
            break;
        }

        result.append(text.substr(pos, nearest - pos));
        result.append(open_tag);
        result.append(text.substr(nearest, terms[term_idx].size()));
        result.append(close_tag);

        pos = nearest + terms[term_idx].size();
    }

    return result;
}

// -------------------------------------------------
// Document Indexing Integration
// Uses the centralized SearchService for index operations
// -------------------------------------------------

/**
 * @brief Index a blog post document using the centralized SearchService
 *
 * This function provides a convenient way to index blog post content
 * using the centralized SearchService. It delegates the actual indexing
 * to SearchService::instance().indexDocument().
 *
 * @param documentId The unique ID of the document to index
 * @param documentContent The text content of the document
 */
void indexBlogPost(int documentId, const std::string& documentContent)
{
    SearchService::instance().indexDocument(documentId, documentContent);
}

/**
 * @brief Query indexed documents using the centralized SearchService
 *
