   380→    void visit(const Node* n)
   381→    {
   382→        if (dynamic_cast<const WordNode*>(n))
   383→            visit_word(static_cast<const WordNode*>(n));
   384→        else if (dynamic_cast<const PhraseNode*>(n))
   385→            visit_phrase(static_cast<const PhraseNode*>(n));
   386→        else if (dynamic_cast<const AndNode*>(n))
   387→            visit_and(static_cast<const AndNode*>(n));
   388→        else if (dynamic_cast<const OrNode*>(n))
   389→            visit_or(static_cast<const OrNode*>(n));
   390→        else if (dynamic_cast<const NotNode*>(n))
   391→            visit_not(static_cast<const NotNode*>(n));
   392→        else
   393→            throw std::runtime_error("Unknown node type in SQL emitter");
   394→    }
