   511→        std::size_t term_idx = 0;
   512→
   513→        for (std::size_t i = 0; i < terms.size(); ++i)
   514→        {
   515→            std::string term_lower = detail::to_lower(terms[i]);
   516→            std::size_t p          = lowered.find(term_lower, pos);
   517→            if (p != std::string::npos && (nearest == std::string::npos || p < nearest))
   518→            {
   519→                nearest  = p;
   520→                term_idx = i;
