   238→    void consume_whitespace()
   239→    {
   240→        while (!eof() && std::isspace(static_cast<unsigned char>(m_query[m_pos])))
   241→            ++m_pos;
   242→    }
   243→
   244→    bool match_keyword(std::string_view kw)
   245→    {
   246→        consume_whitespace();
