    41→/**
    42→ * Convert a human-readable title into an SEO-friendly slug.
    43→ *
    44→ * Rules:
    45→ *  • Lower-case ASCII letters and digits are kept unchanged.
    46→ *  • Upper-case ASCII letters are lower-cased.
    47→ *  • Any other character becomes a hyphen (‘-’).
    48→ *  • Multiple successive hyphens are collapsed.
    49→ *  • Leading/trailing hyphens are trimmed.
    50→ *
    51→ * Thread-safe and allocation-free (aside from the std::string result).
    52→ */
    53→inline std::string slugify(std::string_view input) {
    54→    std::string out;
    55→    out.reserve(input.size());
    56→
    57→    auto push_hyphen = [&]() {
    58→        if (!out.empty() && out.back() != '-') { out.push_back('-'); }
    59→    };
    60→
    61→    for (char ch : input) {
    62→        if (std::isalnum(static_cast<unsigned char>(ch))) {
    63→            out.push_back(static_cast<char>(std::tolower(static_cast<unsigned char>(ch))));
    64→        } else {
    65→            push_hyphen();
    66→        }
    67→    }
    68→    // Trim trailing hyphens
    69→    while (!out.empty() && out.back() == '-') { out.pop_back(); }
    70→    // Trim leading hyphens
    71→    if (!out.empty() && out.front() == '-') { out.erase(out.begin()); }
    72→
    73→    return out;
    74→}
