    40→using DocumentId = std::uint64_t;
    41→
    42→// Simple RAII guard that calls a functor on destruction
    43→template <typename F>
    44→class ScopedGuard {
    45→public:
    46→    explicit ScopedGuard(F f) noexcept : _f(std::move(f)) {}
    47→    ~ScopedGuard() noexcept { _f(); }
    48→    ScopedGuard(const ScopedGuard&) = delete;
    49→    ScopedGuard& operator=(const ScopedGuard&) = delete;
    50→
    51→private:
    52→    F _f;
    53→};
