    55→// -----------------------------------------------------------------------------
    56→//  SearchIndexService
    57→// -----------------------------------------------------------------------------
    58→class SearchIndexService {
    59→public:
    60→    // Obtain singleton instance (thread-safe on C++11 and newer)
    61→    static SearchIndexService& instance() {
    62→        static SearchIndexService g_instance;
    63→        return g_instance;
    64→    }
    65→
    66→    // Public API ---------------------------------------------------------------
    67→    // Schedules a document to be (re)indexed asynchronously
    68→    void scheduleIndexing(DocumentId id, std::string_view text) {
    69→        {
    70→            std::lock_guard<std::mutex> lock(_jobMutex);
    71→            _jobQueue.emplace(Job{ id, std::string(text) });
    72→        }
    73→        _jobCv.notify_one();
    74→    }
    75→
    76→    // Executes a full-text search query. Returns top matching document IDs,
    77→    // ordered by simple TF (term frequency) scoring.
    78→    std::vector<DocumentId> search(std::string_view query, std::size_t limit = 25) const {
    79→        if (query.empty() || limit == 0) { return {}; }
    80→
    81→        // Tokenize once
    82→        const auto tokens = tokenize(query);
    83→
    84→        std::unordered_map<DocumentId, std::size_t> scoreTable;
    85→        {
    86→            std::shared_lock<std::shared_mutex> rlock(_indexMutex);
    87→
    88→            for (const auto& token : tokens) {
    89→                const auto it = _invertedIndex.find(token);
    90→                if (it == _invertedIndex.end()) { continue; }
    91→                for (const auto& docId : it->second) {
    92→                    ++scoreTable[docId];  // simple TF score
    93→                }
    94→            }
    95→        }
    96→
    97→        // Transform map to vector and sort by score descending
    98→        std::vector<std::pair<DocumentId, std::size_t>> ranked(scoreTable.begin(), scoreTable.end());
    99→        std::sort(ranked.begin(), ranked.end(),
   100→                  [](auto&& a, auto&& b) { return a.second > b.second; });
   101→
   102→        if (ranked.size() > limit) { ranked.resize(limit); }
   103→
   104→        std::vector<DocumentId> result;
   105→        result.reserve(ranked.size());
   106→        for (const auto& [docId, _] : ranked) { result.push_back(docId); }
   107→
   108→        return result;
   109→    }
   110→
   111→    // Clean shutdown (useful for unit tests / graceful termination)
   112→    void shutdown() {
   113→        _terminate.store(true, std::memory_order_release);
   114→        _jobCv.notify_one();
   115→        if (_worker.joinable()) { _worker.join(); }
   116→    }
   117→
   118→    // Non-copyable / Non-movable
   119→    SearchIndexService(const SearchIndexService&)            = delete;
   120→    SearchIndexService(SearchIndexService&&)                 = delete;
   121→    SearchIndexService& operator=(const SearchIndexService&) = delete;
   122→    SearchIndexService& operator=(SearchIndexService&&)      = delete;
   123→
   124→private:
   125→    // Background job structure
   126→    struct Job {
   127→        DocumentId      id;
   128→        std::string     text;
   129→    };
   130→
   131→    // Constructor / Destructor -------------------------------------------------
   132→    SearchIndexService()
   133→        : _terminate(false),
   134→          _worker(&SearchIndexService::workerLoop, this) {
   135→        spdlog::info("[SearchIndexService] Initialized.");
   136→    }
   137→
   138→    ~SearchIndexService() {
   139→        shutdown();
   140→        spdlog::info("[SearchIndexService] Destroyed.");
   141→    }
   142→
   143→    // Implementation details ---------------------------------------------------
   144→    static std::vector<std::string> tokenize(std::string_view text) {
   145→        std::vector<std::string> tokens;
   146→
   147→        std::string token;
   148→        token.reserve(32);
   149→
   150→        auto flush = [&]() {
   151→            if (!token.empty()) {
   152→                std::transform(token.begin(), token.end(), token.begin(),
   153→                               [](unsigned char c) { return static_cast<char>(std::tolower(c)); });
   154→                tokens.emplace_back(std::move(token));
   155→                token.clear();
   156→            }
   157→        };
   158→
   159→        for (char ch : text) {
   160→            if (std::isalnum(static_cast<unsigned char>(ch))) {
   161→                token.push_back(ch);
   162→            } else {
   163→                flush();
   164→            }
   165→        }
   166→        flush();
   167→        return tokens;
   168→    }
   169→
   170→    void indexDocument(const Job& job) {
   171→        const auto tokens = tokenize(job.text);
   172→
   173→        // Rebuild per-document token set to avoid duplicates
   174→        std::unordered_set<std::string> uniqueTokens(tokens.begin(), tokens.end());
   175→
   176→        {
   177→            std::unique_lock<std::shared_mutex> wlock(_indexMutex);
   178→
   179→            // For simplicity, first remove previous references to this doc
   180→            for (auto& [word, docset] : _invertedIndex)
   181→                docset.erase(job.id);
   182→
   183→            // Insert new references
   184→            for (const auto& word : uniqueTokens)
   185→                _invertedIndex[word].insert(job.id);
   186→        }
   187→
   188→        spdlog::debug("[SearchIndexService] Indexed document id={} ({} tokens).",
   189→                      job.id, uniqueTokens.size());
   190→    }
   191→
   192→    void workerLoop() {
   193→        spdlog::info("[SearchIndexService] Worker thread started.");
   194→        while (!_terminate.load(std::memory_order_acquire)) {
   195→            Job currentJob;
   196→
   197→            {
   198→                std::unique_lock<std::mutex> lock(_jobMutex);
   199→
   200→                _jobCv.wait(lock, [this] {
   201→                    return !_jobQueue.empty() || _terminate.load(std::memory_order_relaxed);
   202→                });
   203→
   204→                if (_terminate.load(std::memory_order_relaxed)) { break; }
   205→
   206→                currentJob = std::move(_jobQueue.front());
   207→                _jobQueue.pop();
   208→            }
   209→
   210→            // Process outside of lock to minimize contention
   211→            auto guard = ScopedGuard([&] {
   212→                // catch and log any thrown exception to prevent thread exit
   213→                if (std::uncaught_exceptions() > 0) {
   214→                    spdlog::error("[SearchIndexService] uncaught exception during indexing.");
   215→                }
   216→            });
   217→
   218→            try {
   219→                indexDocument(currentJob);
   220→            } catch (const std::exception& ex) {
   221→                spdlog::error("[SearchIndexService] Failed to index doc id={}, reason: {}",
   222→                              currentJob.id, ex.what());
   223→            } catch (...) {
   224→                spdlog::error("[SearchIndexService] Unknown error while indexing doc id={}",
   225→                              currentJob.id);
   226→            }
   227→        }
   228→        spdlog::info("[SearchIndexService] Worker thread exiting.");
   229→    }
   230→
   231→    // State --------------------------------------------------------------------
   232→    // Inverted index: word -> set<docId>
   233→    std::unordered_map<std::string, std::unordered_set<DocumentId>> _invertedIndex;
   234→    mutable std::shared_mutex _indexMutex;
   235→
   236→    // Job queue
   237→    std::queue<Job>  _jobQueue;
   238→    std::mutex       _jobMutex;
   239→    std::condition_variable _jobCv;
   240→
   241→    // Worker
   242→    std::atomic<bool> _terminate;
   243→    std::thread       _worker;
   244→};
   245→
   246→// -----------------------------------------------------------------------------
   247→//  Convenience free functions exposed to other translation units
   248→// -----------------------------------------------------------------------------
   249→void index_document_async(DocumentId id, std::string_view text) {
   250→    SearchIndexService::instance().scheduleIndexing(id, text);
   251→}
   252→
   253→std::vector<DocumentId> query_documents(std::string_view query,
   254→                                        std::size_t limit = 25) {
   255→    return SearchIndexService::instance().search(query, limit);
   256→}
