   258→// -----------------------------------------------------------------------------
   259→//  Example manual test (will be compiled out in release builds)
   260→// -----------------------------------------------------------------------------
   261→#if defined(ILBS_SEARCH_SELFTEST) && !defined(NDEBUG)
   262→#include <iostream>
   263→int main() {
   264→    index_document_async(1, "Hello World, this is a test document.");
   265→    index_document_async(2, "Another document says hello!");
   266→
   267→    // Give the worker a chance to process
   268→    std::this_thread::sleep_for(std::chrono::milliseconds(100));
   269→
   270→    auto hits = query_documents("hello");
   271→    std::cout << "Hits for 'hello': ";
   272→    for (auto h : hits) std::cout << h << " ";
   273→    std::cout << std::endl;
   274→
   275→    SearchIndexService::instance().shutdown();
   276→}
   277→#endif
   278→
   279→} // namespace intraledger::blog::search

