/**
 * @file SearchService.h
 * @brief Centralized search service for IntraLedger BlogSuite
 *
 * This file defines the SearchService class that consolidates all search-related
 * functionality including document indexing and query processing. The service
 * maintains an in-memory inverted index for efficient full-text search operations.
 *
 * Copyright © 2024 IntraLedger
 */

#ifndef INTRALEDGER_SEARCH_SERVICE_H
#define INTRALEDGER_SEARCH_SERVICE_H

#include <map>
#include <mutex>
#include <shared_mutex>
#include <string>
#include <vector>

namespace intraledger::search {

/**
 * @class SearchService
 * @brief Centralized service for document indexing and search query processing
 *
 * The SearchService maintains an in-memory inverted index that maps tokens to
 * document IDs. It provides methods for indexing documents and executing search
 * queries against the indexed content.
 *
 * Thread-safety: All public methods are thread-safe for concurrent access.
 */
class SearchService {
public:
    /**
     * @brief Get the singleton instance of SearchService
     * @return Reference to the global SearchService instance
     */
    static SearchService& instance();

    /**
     * @brief Index a document for full-text search
     *
     * Tokenizes the document content and adds it to the inverted index.
     * If the document was previously indexed, the old index entries are
     * replaced with new ones.
     *
     * @param documentId Unique identifier for the document
     * @param documentContent The text content to be indexed
     */
    void indexDocument(int documentId, const std::string& documentContent);

    /**
     * @brief Execute a search query against the indexed documents
     *
     * Tokenizes the search term and finds all documents containing
     * the specified terms. Results are returned sorted by relevance
     * (number of matching terms).
     *
     * @param searchTerm The search query string
     * @return Vector of document IDs that match the query, sorted by relevance
     */
    std::vector<int> query(const std::string& searchTerm);

    /**
     * @brief Remove a document from the search index
     * @param documentId The ID of the document to remove
     */
    void removeDocument(int documentId);

    /**
     * @brief Clear all indexed documents
     */
    void clearIndex();

    /**
     * @brief Get the number of indexed documents
     * @return Count of unique documents in the index
     */
    std::size_t documentCount() const;

    // Prevent copying and moving
    SearchService(const SearchService&) = delete;
    SearchService& operator=(const SearchService&) = delete;
    SearchService(SearchService&&) = delete;
    SearchService& operator=(SearchService&&) = delete;

private:
    SearchService() = default;
    ~SearchService() = default;

    /**
     * @brief Tokenize text into searchable terms
     *
     * Splits text on whitespace and punctuation, converts to lowercase,
     * and filters out very short tokens.
     *
     * @param text The text to tokenize
     * @return Vector of normalized tokens
     */
    static std::vector<std::string> tokenize(const std::string& text);

    /// Inverted index: token -> list of document IDs
    std::map<std::string, std::vector<int>> invertedIndex;

    /// Mutex for thread-safe access to the inverted index
    mutable std::shared_mutex indexMutex;
};

} // namespace intraledger::search

#endif // INTRALEDGER_SEARCH_SERVICE_H

