   410→        _buffer += "NOT (";
   411→        visit(node->child.get());
   412→        _buffer += ")";
   413→    }
   414→
   415→    void visit_and(const AndNode* node)
   416→    {
   417→        _buffer += "(";
   418→        visit(node->left.get());
   419→        _buffer += " AND ";
   420→        visit(node->right.get());
   421→        _buffer += ")";
   422→    }
   423→
   424→    void visit_or(const OrNode* node)
   425→    {
   426→        _buffer += "(";
   427→        visit(node->left.get());
   428→        _buffer += " OR ";
   429→        visit(node->right.get());
   430→        _buffer += ")";
   431→    }
