void selftest()
{
    QueryParser qp;
    const std::string q = R"(open-source AND ( "zero cost" OR NOT licensing ) )";

    try
    {
        auto parsed = qp.compile(q, "title");

        std::cout << "WHERE: " << parsed.where_clause() << "\n";
        std::cout << "PARAMS:\n";
        for (auto& p : parsed.params())
            std::cout << "  - " << p << "\n";

        // Test SearchService integration
        std::cout << "\nTesting SearchService integration:\n";
        indexBlogPost(1, "This is a test article about open-source software");
        indexBlogPost(2, "Another article about licensing and zero cost solutions");

        auto results = searchBlogPosts("open-source");
        std::cout << "Search results for 'open-source': ";
        for (int id : results)
            std::cout << id << " ";
        std::cout << "\n";
    }
    catch (const std::exception& ex)
    {
        std::cerr << "Error: " << ex.what() << '\n';
    }
}

int main()
{
    selftest();
    return 0;
}
#endif

