   108→inline std::string normalize_utf8(std::string_view src)
   109→{
   110→    utf8proc_uint8_t const* data =
   111→        reinterpret_cast<const utf8proc_uint8_t*>(src.data());
   112→    utf8proc_uint8_t* result = nullptr;
   113→
   114→    auto len = utf8proc_decompose(data, src.size(), &result,
