   131→
   132→enum class BoolOperator
   133→{
   134→    And,
   135→    Or
   136→};
   137→
   138→// Forward declaration
   139→struct Node;
   140→
   141→using NodePtr = std::shared_ptr<Node>;
   142→
   143→/**
   144→ *  Base search AST node
   145→ */
   146→struct Node
   147→{
   148→    virtual ~Node() = default;
   149→    virtual std::string to_sql(std::vector<std::string>& out_params) const = 0;
   150→};
   151→
   152→/**
   153→ *  Represents a single token (word, phrase) possibly preceded by NOT.
   154→ */
   155→struct TermNode final : public Node
   156→{
   157→    std::string  token;
   158→    bool         negated { false };
   159→
   160→    explicit TermNode(std::string token_, bool neg = false)
   161→        : token(std::move(token_)), negated(neg) {}
   162→
   163→    std::string to_sql(std::vector<std::string>& out_params) const override
   164→    {
   165→        std::string like_pattern = fmt::format("%{}%", util::sql_escape(token));
   166→        out_params.push_back(like_pattern);
   167→
   168→        if (negated)
   169→            return "content NOT ILIKE ?";
   170→        else
   171→            return "content ILIKE ?";
   172→    }
   173→};
   174→
   175→/**
   176→ *  Logical grouping node (AND / OR)
   177→ */
   178→struct BoolNode final : public Node
   179→{
   180→    BoolOperator                op;
   181→    std::vector<std::shared_ptr<Node>> children;
   182→
   183→    BoolNode(BoolOperator op_, std::vector<NodePtr> ch)
   184→        : op(op_), children(std::move(ch)) {}
   185→
   186→    std::string to_sql(std::vector<std::string>& out_params) const override
   187→    {
   188→        if (children.empty())
   189→            return "TRUE";
   190→
   191→        std::string_view op_str = (op == BoolOperator::And) ? "AND" : "OR";
   192→
   193→        std::vector<std::string> child_sql;
   194→        child_sql.reserve(children.size());
   195→        for (auto const& c : children)
   196→            child_sql.push_back(c->to_sql(out_params));
   197→
   198→        return fmt::format("({})",
   199→                           fmt::join(child_sql, fmt::format(" {} ", op_str)));
   200→    }
   201→};
