   113→/**
   114→ *  Normalize UTF-8 string into NFC.
   115→ */
   116→inline std::string normalize_utf8(std::string_view src)
   117→{
   118→    utf8proc_uint8_t const* data =
   119→        reinterpret_cast<const utf8proc_uint8_t*>(src.data());
   120→    utf8proc_uint8_t* result = nullptr;
   121→
   122→    auto len = utf8proc_decompose(data, src.size(), &result,
   123→                                  UTF8PROC_NULLTERM | UTF8PROC_COMPOSE);
   124→
   125→    if (len < 0)
   126→        throw std::runtime_error("utf8proc_decompose() failed");
   127→
   128→    std::string normalized(reinterpret_cast<char*>(result), len);
