   160→/**
   161→ *  Represents a single token (word, phrase) possibly preceded by NOT.
   162→ */
   163→struct TermNode final : public Node
   164→{
   165→    std::string  token;
   166→    bool         negated { false };
   167→
   168→    explicit TermNode(std::string token_, bool neg = false)
   169→        : token(std::move(token_)), negated(neg) {}
   170→
   171→    std::string to_sql(std::vector<std::string>& out_params) const override
   172→    {
   173→        std::string like_pattern = fmt::format("%{}%", util::sql_escape(token));
   174→        out_params.push_back(like_pattern);
   175→
   176→        if (negated)
   177→            return "content NOT ILIKE ?";
   178→        else
   179→            return "content ILIKE ?";
   180→    }
   181→};
   182→
   183→/**
   184→ *  Logical grouping node (AND / OR)
   185→ */
   186→struct BoolNode final : public Node
   187→{
   188→    BoolOperator                op;
   189→    std::vector<std::shared_ptr<Node>> children;
   190→
   191→    BoolNode(BoolOperator op_, std::vector<NodePtr> ch)
   192→        : op(op_), children(std::move(ch)) {}
   193→
   194→    std::string to_sql(std::vector<std::string>& out_params) const override
   195→    {
   196→        if (children.empty())
   197→            return "TRUE";
   198→
   199→        std::string_view op_str = (op == BoolOperator::And) ? "AND" : "OR";
   200→
   201→        std::vector<std::string> child_sql;
   202→        child_sql.reserve(children.size());
   203→        for (auto const& c : children)
   204→            child_sql.push_back(c->to_sql(out_params));
   205→
   206→        return fmt::format("({})",
   207→                           fmt::join(child_sql, fmt::format(" {} ", op_str)));
   208→    }
   209→};
