   211→//------------------------------------------------------------------------------
   212→// Recursive-descent parser for simple boolean query grammar
   213→// Supports:
   214→//      term           -> WORD | "PHRASE"
   215→//      factor         -> [NOT] term
   216→//      expr_and       -> factor { AND factor }
   217→//      expr_or        -> expr_and { OR expr_and }
   218→//      query          -> expr_or
   219→//--------------------------------------------------------------------------
   220→
   221→class QueryParser
   222→{
   223→public:
   224→    explicit QueryParser(std::string_view q)
   225→        : m_query(q)
   226→    {
   227→        util::ascii_to_lower(m_query); // case-folding
   228→    }
   229→
   230→    NodePtr parse()
   231→    {
   232→        m_pos = 0;
   233→        NodePtr root = parse_or();
   234→        consume_whitespace();
   235→        if (m_pos != m_query.size())
   236→            throw std::runtime_error("Unexpected trailing characters");
   237→        return root;
   238→    }
   239→
   240→private:
   241→    std::string m_query;
   242→    std::size_t m_pos { 0 };
   243→
   244→    [[nodiscard]] bool eof() const noexcept { return m_pos >= m_query.size(); }
   245→
   246→    void consume_whitespace()
   247→    {
   248→        while (!eof() && std::isspace(static_cast<unsigned char>(m_query[m_pos])))
   249→            ++m_pos;
   250→    }
   251→
   252→    bool match_keyword(std::string_view kw)
   253→    {
   254→        consume_whitespace();
   255→        if (m_query.compare(m_pos, kw.size(), kw) == 0)
   256→        {
   257→            const auto next = m_pos + kw.size();
   258→            if (next == m_query.size() || std::isspace(static_cast<unsigned char>(m_query[next])))
   259→            {
   260→                m_pos = next;
   261→                return true;
   262→            }
   263→        }
   264→        return false;
   265→    }
   266→
   267→    NodePtr parse_or()
   268→    {
   269→        std::vector<NodePtr> nodes;
   270→        nodes.push_back(parse_and());
   271→        while (match_keyword("or"))
   272→            nodes.push_back(parse_and());
   273→
   274→        if (nodes.size() == 1)
   275→            return nodes.front();
   276→        return std::make_shared<BoolNode>(BoolOperator::Or, std::move(nodes));
   277→    }
   278→
   279→    NodePtr parse_and()
   280→    {
   281→        std::vector<NodePtr> nodes;
   282→        nodes.push_back(parse_factor());
   283→        while (match_keyword("and"))
   284→            nodes.push_back(parse_factor());
   285→
   286→        if (nodes.size() == 1)
   287→            return nodes.front();
   288→        return std::make_shared<BoolNode>(BoolOperator::And, std::move(nodes));
   289→    }
   290→
   291→    NodePtr parse_factor()
   292→    {
   293→        consume_whitespace();
   294→        bool neg = false;
   295→        if (match_keyword("not"))
   296→            neg = true;
   297→
   298→        return parse_term(neg);
   299→    }
   300→
   301→    NodePtr parse_term(bool negated)
   302→    {
   303→        consume_whitespace();
   304→        if (eof())
   305→            throw std::runtime_error("Unexpected end of query");
   306→
   307→        char ch = m_query[m_pos];
   308→        if (ch == '"')
   309→        {
   310→            ++m_pos;
   311→            std::size_t end = m_query.find('"', m_pos);
   312→            if (end == std::string::npos)
   313→                throw std::runtime_error("Unterminated quote");
   314→
   315→            std::string phrase = m_query.substr(m_pos, end - m_pos);
   316→            m_pos = end + 1;
   317→            return std::make_shared<TermNode>(std::move(phrase), negated);
   318→        }
   319→
   320→        // Word
   321→        std::size_t start = m_pos;
   322→        while (!eof() && !std::isspace(static_cast<unsigned char>(m_query[m_pos])))
   323→            ++m_pos;
   324→
   325→        std::string word = m_query.substr(start, m_pos - start);
   326→        return std::make_shared<TermNode>(std::move(word), negated);
   327→    }
   328→};
