   360→/**
   361→ *  Very naive TF-IDF style scoring.  In production use, replace with proper
   362→ *  full-text search (PostgreSQL tsvector/tsquery or Elasticsearch), but this
   363→ *  algorithm is serviceable for demo purposes without extra dependencies.
   364→ */
   365→double score_document(std::string_view text,
   366→                      const std::vector<std::string>& search_terms)
   367→{
   368→    if (search_terms.empty())
   369→        return 0.0;
   370→
   371→    std::unordered_map<std::string, int> word_freq;
   372→    std::istringstream iss{std::string(text)};
   373→    std::string word;
   374→    while (iss >> word)
   375→    {
   376→        util::ascii_to_lower(word);
   377→        ++word_freq[word];
   378→    }
   379→
   380→    int term_hits = 0;
   381→    for (auto const& term : search_terms)
   382→    {
   383→        auto it = word_freq.find(term);
   384→        if (it != word_freq.end())
   385→            term_hits += it->second;
   386→    }
   387→
   388→    double score = static_cast<double>(term_hits) / static_cast<double>(word_freq.size() + 1);
   389→    return score;
   390→}
