   392→/**
   393→ *  Retrieve a highlighted snippet around the first term hit.
   394→ */
   395→std::string make_snippet(std::string_view text,
   396→                         const std::vector<std::string>& search_terms,
   397→                         std::size_t context = 40)
   398→{
   399→    std::string lowercase{ text };
   400→    util::ascii_to_lower(lowercase);
   401→
   402→    std::size_t best_pos = std::string_view::npos;
   403→    for (const auto& term : search_terms)
   404→    {
   405→        std::size_t pos = lowercase.find(term);
   406→        if (pos != std::string_view::npos &&
   407→            (best_pos == std::string_view::npos || pos < best_pos))
   408→            best_pos = pos;
   409→    }
   410→
   411→    if (best_pos == std::string_view::npos)
   412→        return std::string(text.substr(0, std::min(text.size(), context))) + "...";
   413→
   414→    std::size_t start = (best_pos > context) ? best_pos - context : 0;
   415→    std::size_t end   = std::min(text.size(), best_pos + context);
   416→
   417→    std::string snippet = std::string(text.substr(start, end - start));
   418→    // crude HTML highlight
   419→    for (const auto& term : search_terms)
   420→    {
   421→        std::regex rgx(term, std::regex_constants::icase);
   422→        snippet = std::regex_replace(snippet, rgx, "<mark>$&</mark>");
   423→    }
   424→
   425→    if (start != 0)
   426→        snippet.insert(0, "...");
   427→    if (end != text.size())
   428→        snippet.append("...");
   429→    return snippet;
   430→}
