   434→//------------------------------------------------------------------------------
   435→// SQL-based Search Service (for database queries)
   436→// Uses the centralized SearchService for in-memory index operations
   437→//------------------------------------------------------------------------------
   438→
   439→class DatabaseSearchService
   440→{
   441→public:
   442→    explicit DatabaseSearchService(std::shared_ptr<IArticleRepository> repo)
   443→        : m_repo(std::move(repo))
   444→    {
   445→        if (!m_repo)
   446→            throw std::invalid_argument("DatabaseSearchService requires a repository");
   447→    }
   448→
   449→    struct Result
   450→    {
   451→        ArticleDTO  article;
   452→        double      score;
   453→        std::string snippet;
   454→    };
   455→
   456→    /**
   457→     * Search using database SQL queries (for complex boolean queries)
   458→     */
   459→    std::vector<Result> search(std::string_view query,
   460→                               std::size_t limit  = 50,
   461→                               std::size_t offset = 0)
   462→    {
   463→        if (query.size() < 2)
   464→            return {}; // ignore noise
   465→
   466→#ifdef SEARCH_UTF8_NORMALIZE
   467→        query = util::normalize_utf8(query);
   468→#endif
   469→
   470→        // Step 1: Parse
   471→        std::vector<std::string> bound_params;
   472→        auto ast  = QueryParser{query}.parse();
   473→        auto where_clause = ast->to_sql(bound_params);
   474→
   475→        // Step 2: Fetch data
   476→        auto records = m_repo->search(where_clause, bound_params, limit, offset);
   477→
   478→        // Step 3: Score + snippet
   479→        std::vector<std::string> search_terms = collect_terms(ast);
   480→        std::vector<Result> out;
   481→        out.reserve(records.size());
   482→
   483→        for (auto&& rec : records)
   484→        {
   485→            double sc = ranking::score_document(rec.content, search_terms);
   486→            std::string snip = ranking::make_snippet(rec.content, search_terms);
   487→            out.push_back(Result{std::move(rec), sc, std::move(snip)});
   488→        }
   489→
   490→        // Step 4: Sort by score desc, then published_at desc
   491→        std::ranges::stable_sort(out, [](auto const& a, auto const& b)
   492→        {
   493→            if (a.score != b.score)
   494→                return a.score > b.score;
   495→            return a.article.published_at > b.article.published_at;
   496→        });
   497→
   498→        spdlog::info("Database search for '{}' returned {} documents", query, out.size());
   499→        return out;
   500→    }
   501→
   502→    /**
   503→     * Search using the centralized in-memory index (for fast lookups)
   504→     * Delegates to the centralized SearchService
   505→     */
   506→    std::vector<int> searchIndex(const std::string& query)
   507→    {
   508→        return intraledger::search::SearchService::instance().query(query);
   509→    }
   510→
   511→    /**
   512→     * Index a document using the centralized SearchService
   513→     * Delegates to the centralized SearchService
   514→     */
   515→    void indexDocument(int documentId, const std::string& content)
   516→    {
   517→        intraledger::search::SearchService::instance().indexDocument(documentId, content);
   518→    }
   519→
   520→private:
   521→    std::shared_ptr<IArticleRepository> m_repo;
   522→
   523→    static void collect_terms_recursive(const NodePtr& node,
   524→                                        std::vector<std::string>& dst)
   525→    {
   526→        if (!node)
   527→            return;
   528→
   529→        if (auto term = std::dynamic_pointer_cast<TermNode>(node))
   530→        {
   531→            dst.push_back(term->token);
   532→            return;
   533→        }
   534→
   535→        if (auto group = std::dynamic_pointer_cast<BoolNode>(node))
   536→        {
   537→            for (auto const& ch : group->children)
   538→                collect_terms_recursive(ch, dst);
   539→        }
   540→    }
   541→
   542→    static std::vector<std::string> collect_terms(const NodePtr& ast)
   543→    {
   544→        std::vector<std::string> terms;
   545→        collect_terms_recursive(ast, terms);
   546→        return terms;
   547→    }
   548→};
