ze());", "+        spdlog::info(\"Database search for '{}' returned {} documents\", query, out.size());", "         return out;", "     }", " ", "+    /**", "+     * Search using the centralized in-memory index (for fast lookups)", "+     * Delegates to the centralized SearchService", "+     */", "+    std::vector<int> searchIndex(const std::string& query)", "+    {", "+        return intraledger::search::SearchService::instance().query(query);", "+    }", "+", "+    /**", "+     * Index a document using the centralized SearchService", "+     * Delegates to the centralized SearchService", "+     */", "+    void indexDocument(int documentId, const std::string& content)", "+    {", "+        intraledger::search::SearchService::instance().indexDocument(documentId, content);", "+    }", "+", " private:", "     std::shared_ptr<IArticleRepository> m_repo;", " "]}, {"oldStart": 518, "oldLines": 6, "newStart": 548, "newLines": 26, "lines": [" };", " ", " //------------------------------------------------------------------------------", "+// Convenience functions using the centralized SearchService", "+//------------------------------------------------------------------------------", "+", "+/**", "+ * @brief Index a document using the centralized SearchService", "+ */", "+void indexDocument(int documentId, const std::string& documentContent)", "+{", "+    intraledger::search::SearchService::instance().indexDocument(documentId, documentContent);", "+}", "+", "+/**", "+ * @brief Query documents using the centralized SearchService", "+ */", "+std::vector<int> queryDocuments(const std::string& searchTerm)", "+{", "+    return intraledger::search::SearchService::instance().query(searchTerm);", "+}", "+", "+//------------------------------------------------------------------------------", " // Dummy repository for demonstration / unit tests", " //------------------------------------------------------------------------------", " "]}, {"oldStart": 572, "oldLines": 13, "newStart": 62