   486→    std::string              sql;     // WHERE clause without the "WHERE" keyword
   487→    std::vector<std::string> params;  // positional parameters to bind in order
   488→};
   489→
   490→class SqlTranslator
   491→{
   492→public:
   493→    // Compile AST into SQL WHERE fragment
   494→    SqlFragment compile(const QueryNode& root)
   495→    {
   496→        m_buffer.clear();
   497→        m_params.clear();
   498→        walk(root);
   499→        return { m_buffer.str(), m_params };
   500→    }
   501→
   502→private:
   503→    std::ostringstream        m_buffer;
   504→    std::vector<std::string>  m_params;
   505→
   506→    // Depth-first traversal
   507→    void walk(const QueryNode& node)
   508→    {
   509→        std::visit([this](auto&& n) { generate(n); }, node);
   510→    }
   511→
   512→    // Generates SQL with PostgreSQL/MariaDB full-text search in mind.
   513→    // The ORM will later splice this fragment into a larger statement.
   514→    void generate(const Term& n)
   515→    {
   516→        emit_param(to_tsquery(n.value));
   517→    }
   518→
   519→    void generate(const Phrase& n)
   520→    {
   521→        emit_param(to_tsquery_phrase(n.value));
   522→    }
   523→
   524→    void generate(const FieldFilter& n)
   525→    {
   526→        m_buffer << '(';
   527→        const std::string columnName = map_field_to_column(n.field);
   528→        m_buffer << columnName << " @@ ";
   529→        walk(*n.arg);
   530→        m_buffer << ')';
   531→    }
   532→
   533→    void generate(const Not& n)
   534→    {
   535→        m_buffer << "NOT (";
   536→        walk(*n.arg);
   537→        m_buffer << ')';
   538→    }
   539→
   540→    void generate(const And& n)
   541→    {
   542→        m_buffer << '(';
   543→        walk(*n.lhs);
   544→        m_buffer << " AND ";
   545→        walk(*n.rhs);
   546→        m_buffer << ')';
   547→    }
   548→
   549→    void generate(const Or& n)
   550→    {
   551→        m_buffer << '(';
   552→        walk(*n.lhs);
   553→        m_buffer << " OR ";
   554→        walk(*n.rhs);
   555→        m_buffer << ')';
   556→    }
   557→
   558→    // Helpers ────────────────────────────────────────────────────────────────
   559→
   560→    static std::string to_tsquery(const std::string& term)
   561→    {
   562→        // Simplistic sanitisation; production code would do stemming, etc.
   563→        std::string sanitized;
   564→        sanitized.reserve(term.size());
   565→        for (char c : term)
   566→        {
   567→            if (std::isalnum(static_cast<unsigned char>(c)) || c == '_')
   568→                sanitized.push_back(static_cast<char>(std::tolower(c)));
   569→        }
   570→        return sanitized + ":*"; // prefix search
   571→    }
   572→
   573→    static std::string to_tsquery_phrase(const std::string& phrase)
   574→    {
   575→        // Replace spaces with & to enforce term adjacency in tsquery
   576→        std::string ts = phrase;
   577→        std::replace(ts.begin(), ts.end(), ' ', '&');
   578→        return ts;
   579→    }
